import io
import os

import torch
import torch.nn.functional as F
from PIL import Image
from torchvision import transforms
from torchvision import models
from flask import Flask, request, jsonify

app = Flask(__name__)

# --- Model Loading ---
# You can replace this with your own trained model.
# For demonstration, we'll use a pre-trained ResNet-18
# and define a dummy class list.
try:
    model = models.resnet18(pretrained=True)
    # The last layer needs to match the number of your specific classes
    # For ImageNet, it's 1000 classes. If you have fewer, adjust it.
    num_ftrs = model.fc.in_features
    # Example: If you had 10 classes
    # model.fc = torch.nn.Linear(num_ftrs, 10)
    model.eval() # Set the model to evaluation mode
    print("Pre-trained ResNet-18 loaded successfully.")
except Exception as e:
    print(f"Error loading model: {e}")
    # Exit or handle gracefully if model loading is critical
    model = None

# Dummy class names for demonstration (replace with your actual class names)
# If using pre-trained ImageNet models, you'd typically load ImageNet class labels.
IMAGENET_CLASSES = [f"class_{i}" for i in range(1000)] # Placeholder
try:
    # A more robust way to get ImageNet classes if using pre-trained models
    # This requires downloading the file or having it locally
    imagenet_labels_path = "imagenet_classes.txt" # Adjust path as needed
    if os.path.exists(imagenet_labels_path):
        with open(imagenet_labels_path, "r") as f:
            IMAGENET_CLASSES = [line.strip() for line in f.readlines()]
        print(f"Loaded {len(IMAGENET_CLASSES)} ImageNet class labels.")
    else:
        print(f"Warning: {imagenet_labels_path} not found. Using dummy class labels.")
except Exception as e:
    print(f"Error loading ImageNet class labels: {e}")
    IMAGENET_CLASSES = [f"class_{i}" for i in range(1000)]


# --- Preprocessing Transformation ---
# These are standard transformations for pre-trained ImageNet models.
# Adjust if your model requires different input.
preprocess = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

@app.route('/predict', methods=['POST'])
def predict():
    if model is None:
        return jsonify({"error": "Model not loaded. Cannot perform inference."}), 500

    if 'image' not in request.files:
        return jsonify({"error": "No image file provided."}), 400

    image_file = request.files['image']

    try:
        # Read the image file directly from the request stream
        img_bytes = image_file.read()
        img = Image.open(io.BytesIO(img_bytes)).convert('RGB')
    except Exception as e:
        return jsonify({"error": f"Could not read or open image: {str(e)}"}), 400

    # Apply preprocessing
    input_tensor = preprocess(img)
    input_batch = input_tensor.unsqueeze(0)  # Create a mini-batch as expected by the model

    # Move the input to the same device as the model (CPU or GPU)
    device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
    model.to(device)
    input_batch = input_batch.to(device)

    with torch.no_grad():
        output = model(input_batch)

    # Get probabilities by applying softmax
    probabilities = F.softmax(output, dim=1)[0]

    # Get the predicted class index and confidence
    confidence, predicted_idx = torch.max(probabilities, 0)
    
    # Map the index to the class name
    predicted_class = IMAGENET_CLASSES[predicted_idx.item()]

    return jsonify({
        "predicted_class": predicted_class,
        "confidence": confidence.item()
    })

if __name__ == '__main__':
    # To run the app: python your_script_name.py
    # Then access it at http://127.0.0.1:5000/predict
    # You can send a POST request with an image file named 'image'
    # Example using curl:
    # curl -X POST -F "image=@path/to/your/image.jpg" http://127.0.0.1:5000/predict
    app.run(debug=True, host='0.0.0.0', port=5000)